#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <omp.h>
#include <time.h>

#define BLOCK_SIZE 16

void random_matrix(float *I, int rows, int cols);
void runTest(int argc, char **argv);
void usage(int argc, char **argv) {
    fprintf(stderr, "Usage: %s <rows> <cols> <y1> <y2> <x1> <x2> <lamda> <no. of iter>\n", argv[0]);
    fprintf(stderr, "\t<rows>   - number of rows\n");
    fprintf(stderr, "\t<cols>    - number of cols\n");
    fprintf(stderr, "\t<y1> 	 - y1 value of the speckle\n");
    fprintf(stderr, "\t<y2>      - y2 value of the speckle\n");
    fprintf(stderr, "\t<x1>       - x1 value of the speckle\n");
    fprintf(stderr, "\t<x2>       - x2 value of the speckle\n");
    fprintf(stderr, "\t<lamda>   - lambda (0,1)\n");
    fprintf(stderr, "\t<no. of iter>   - number of iterations\n");

    exit(1);
}

int main(int argc, char **argv) {
    printf("WG size of kernel = %d X %d\n", BLOCK_SIZE, BLOCK_SIZE);
    runTest(argc, argv);

    return EXIT_SUCCESS;
}

void runTest(int argc, char **argv) {
    int rows, cols, size_I, size_R, niter = 10, iter;
    float *I, *J, lambda, q0sqr, sum, sum2, tmp, meanROI, varROI;

    float *c;
    unsigned int r1, r2, c1, c2;

    if (argc == 9) {
        rows = atoi(argv[1]);  //number of rows in the domain
        cols = atoi(argv[2]);  //number of cols in the domain
        if ((rows % 16 != 0) || (cols % 16 != 0)) {
            fprintf(stderr, "rows and cols must be multiples of 16\n");
            exit(1);
        }
        r1 = atoi(argv[3]);  //y1 position of the speckle
        r2 = atoi(argv[4]);  //y2 position of the speckle
        c1 = atoi(argv[5]);  //x1 position of the speckle
        c2 = atoi(argv[6]);  //x2 position of the speckle
        lambda = atof(argv[7]); //Lambda value
        niter = atoi(argv[8]); //number of iterations

    } else {
        usage(argc, argv);
    }

    size_I = cols * rows;
    size_R = (r2 - r1 + 1) * (c2 - c1 + 1);

    I = (float *)malloc(size_I * sizeof(float));
    J = (float *)malloc(size_I * sizeof(float));
    c = (float *)malloc(size_I * sizeof(float));

    printf("Randomizing the input matrix\n");
    //Generate a random matrix
    random_matrix(I, rows, cols);

    for (int k = 0; k < size_I; k++) {
        J[k] = (float)exp(I[k]);
    }
    printf("Start the SRAD main loop\n");
    for (iter = 0; iter < niter; iter++) {
        sum = 0; sum2 = 0;
        for (int i = r1; i <= r2; i++) {
            for (int j = c1; j <= c2; j++) {
                tmp = J[i * cols + j];
                sum += tmp;
                sum2 += tmp * tmp;
            }
        }
        meanROI = sum / size_R;
        varROI = (sum2 / size_R) - meanROI * meanROI;
        q0sqr = varROI / (meanROI * meanROI);

        #pragma omp parallel for
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                int k = i * cols + j;
                float Jc = J[k];
                float dN, dS, dW, dE, G2, L, num, den, qsqr;

                if (i == 0) dN = J[k] - J[k];
                else dN = J[(i - 1) * cols + j] - Jc;

                if (i == rows - 1) dS = J[k] - J[k];
                else dS = J[(i + 1) * cols + j] - Jc;

                if (j == 0) dW = J[k] - J[k];
                else dW = J[i * cols + j - 1] - Jc;

                if (j == cols - 1) dE = J[k] - J[k];
                else dE = J[i * cols + j + 1] - Jc;

                G2 = (dN * dN + dS * dS + dW * dW + dE * dE) / (Jc * Jc);
                L = (dN + dS + dW + dE) / Jc;

                num = (0.5 * G2) - ((1.0 / 16.0) * (L * L));
                den = 1 + (.25 * L);
                qsqr = num / (den * den);

                // diffusion coefficent (equ 33)
                den = (qsqr - q0sqr) / (q0sqr * (1 + q0sqr));
                c[k] = 1.0 / (1.0 + den);

                // saturate diffusion coefficent
                if (c[k] < 0) c[k] = 0;
                else if (c[k] > 1) c[k] = 1;
            }
        }

        #pragma omp parallel for
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                int k = i * cols + j;
                float cc, cn, cs, ce, cw, d_sum;

                if (i == 0) cn = c[k];
                else cn = c[(i - 1) * cols + j];

                if (i == rows - 1) cs = c[k];
                else cs = c[(i + 1) * cols + j];

                if (j == 0) cw = c[k];
                else cw = c[i * cols + j - 1];

                if (j == cols - 1) ce = c[k];
                else ce = c[i * cols + j + 1];

                cc = c[k];

                float dN, dS, dW, dE;
                if (i == 0) dN = J[k] - J[k];
                else dN = J[(i - 1) * cols + j] - J[k];

                if (i == rows - 1) dS = J[k] - J[k];
                else dS = J[(i + 1) * cols + j] - J[k];

                if (j == 0) dW = J[k] - J[k];
                else dW = J[i * cols + j - 1] - J[k];

                if (j == cols - 1) dE = J[k] - J[k];
                else dE = J[i * cols + j + 1] - J[k];

                // divergence (equ 58)
                d_sum = cn * dN + cs * dS + cw * dW + ce * dE;

                // image update (equ 61)
                J[k] = J[k] + 0.25 * lambda * d_sum;
            }
        }
    }

    #ifdef OUTPUT
    //Printing output
    printf("Printing Output:\n");
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            printf("%.5f ", J[i * cols + j]);
        }
        printf("\n");
    }
    #endif

    printf("Computation Done\n");

    free(I);
    free(J);
    free(c);
}

void random_matrix(float *I, int rows, int cols) {
    srand(7);

    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            I[i * cols + j] = (float)rand() / RAND_MAX;
        }
    }
}
